---
import { AstroSeo } from "@lexingtonthemes/seo"
import type { ImageMetadata } from "astro"
import { getImage } from "astro:assets"

type Props = {
  name?: string
  title?: string
  description?: string
  image?: {
    src?: ImageMetadata | string
    alt?: string
  }
  noindex?: boolean
  nofollow?: boolean
  canonical?: string
}

const baseUrl = Astro.site?.origin || Astro.url.origin
const pagePathname = Astro.url.pathname.endsWith("/")
  ? Astro.url.pathname
  : `${Astro.url.pathname}/`

const {
  name,
  title,
  description,
  image,
  noindex,
  nofollow,
  canonical,
  ...props
} = Astro.props

const resolvedCanonical = new URL(canonical || pagePathname, baseUrl).toString()

const toImageMimeType = (format?: string) => {
  if (!format) return undefined
  if (format.includes("/")) return format
  if (format === "jpg") return "image/jpeg"
  return `image/${format}`
}

const transformedImage =
  image?.src && typeof image.src !== "string"
    ? await getImage({
        src: image.src,
        format: "png",
        width: 1200,
        height: 630,
        quality: "medium",
      })
    : undefined

const openGraphImage =
  typeof image?.src === "string"
    ? {
        url: new URL(image.src, baseUrl).toString(),
        alt: image.alt,
      }
    : transformedImage
      ? {
          url: new URL(transformedImage.src, baseUrl).toString(),
          alt: image?.alt,
          width: transformedImage.attributes.width,
          height: transformedImage.attributes.height,
          type: toImageMimeType(transformedImage.attributes.format),
        }
      : undefined
---

<head data-slot="layout-head" {...props}>
  <meta charset="utf-8" />
  <AstroSeo
    title={title}
    description={description}
    canonical={resolvedCanonical}
    noindex={noindex}
    nofollow={nofollow}
    openGraph={{
      url: resolvedCanonical,
      type: "website",
      ...(name && { site_name: name }),
      ...(openGraphImage && {
        images: [
          {
            ...openGraphImage,
            ...(openGraphImage.url.startsWith("https://") && {
              secureUrl: openGraphImage.url,
            }),
          },
        ],
      }),
    }}
  />
  <slot />
</head>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"body">

const { class: className, ...props } = Astro.props
---

<body
  class={cn(
    "bg-background text-foreground overscroll-none antialiased",
    className
  )}
  data-slot="layout-body"
  {...props}
>
  <slot />
</body>

<style is:global>
  body {
    font-family: var(--font-sans);
  }
</style>

---
import type { HTMLAttributes } from "astro/types"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const variants = cva("@container flex flex-col", {
  variants: {
    inset: {
      none: "",
      contained:
        "bg-background relative mx-auto mb-2 w-[calc(100%-2*var(--gutter,24px))] max-w-(--header-width) flex-1 overflow-hidden rounded-xl shadow-sm",
      full: "bg-background relative mx-auto mb-2 w-[calc(100%-2*var(--gutter,24px))] max-w-none flex-1 overflow-hidden rounded-xl shadow-sm",
    },
  },
  defaultVariants: {
    inset: "none",
  },
})

type Props = HTMLAttributes<"main"> &
  VariantProps<typeof variants> & {
    as?: "div" | "main"
  }

const { as = "main", class: className, inset, ...props } = Astro.props
const Tag = as
---

<Tag
  data-inset={inset === "none" ? undefined : inset}
  data-slot="layout-main"
  class={cn(variants({ inset }), className)}
  {...props}
>
  <slot />
</Tag>
